import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw['topLevelPackages']:
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or '(none)', av or '(none)'))
    else:
        unchanged.append((k[0], k[1], k[2], av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]}')
else:
    print('  (none)')

print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for u in unchanged:
    print(f'  {u[0]:20s} {u[1]:10s} {u[2]:50s} {u[3]}')
"

